CREATE OR REPLACE FUNCTION fpa_acc_valid_relate_bank (as_accid char) RETURNS char AS $body$
DECLARE

  ls_account_control_id sc_acc_m_account_master.account_control_id%type;

BEGIN
  select account_control_id into STRICT ls_account_control_id
  from sc_acc_m_account_master
  where (account_id = as_accid);
  if ls_account_control_id in ('110200','110300','110400','410300','410400') then
    return '1';
  end if;
  return '0';
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
